+export function smoothDuration(observations: DurationObservation[], method: 'latest' | 'average' | 'p95' | 'median'): number {
+  if (!observations.length) return 0
+  const values = observations.map(o => o.duration).sort((a, b) => a - b)
+  if (method === 'latest') return observations.reduce((latest, value) => value.recordedAt > latest.recordedAt ? value : latest).duration
+  if (method === 'average') return Math.round(values.reduce((sum, value) => sum + value, 0) / values.length)
+  if (method === 'p95') return values[Math.ceil(.95 * values.length) - 1]
+  const middle = Math.floor(values.length / 2)
+  return values.length % 2 ? values[middle] : Math.floor((values[middle - 1] + values[middle]) / 2)
